def validate_package_name(package_spec):
    if not package_spec or not isinstance(package_spec, str):
        return False
    
    dangerous_chars = [';', '&', '|', '`', '$', '(', ')', '<', '>', '\n', '\r']
    if any(char in package_spec for char in dangerous_chars):
        return False
    
    parts = package_spec.split('==')
    if len(parts) > 2:
        return False
    
    package_name = parts[0].strip()
    if not package_name or not all(c.isalnum() or c in '-_.' for c in package_name):
        return False
    
    if len(parts) == 2:
        version = parts[1].strip()
        if not version or not all(c.isdigit() or c in '.-' for c in version):
            return False
    
    return True


